const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || {};
const envToken = typeof $env !== 'undefined' ? $env.N8N_WEBHOOK_TOKEN : undefined;
const processToken = typeof process !== 'undefined' ? process.env.N8N_WEBHOOK_TOKEN : undefined;
const expectedToken = envToken || processToken || '';
const actualToken = headers['x-servicedesk-token'] || headers['X-ServiceDesk-Token'] || headers['X-Servicedesk-Token'] || '';

if (!expectedToken || actualToken !== expectedToken) {
  return [
    {
      json: {
        statusCode: 401,
        response: {
          error: {
            code: 'unauthorized',
            message: 'Токен webhook отсутствует или некорректен.'
          }
        }
      }
    }
  ];
}

return [
  {
    json: {
      statusCode: 200,
      response: {
        runbook_status: 'accepted',
        message: 'n8n webhook ранбука этапа 4 получил авторизованный запрос.',
        invocation_id: body.invocation?.invocation_id,
        action_id: body.invocation?.action_id,
        parameters: body.parameters || {}
      }
    }
  }
];
